// CVE/Threat: AWS AiTM Phishing Kit Steals Console Credentials and MFA Codes in Real Time | Generated: 2026-06-25T18:39:25Z
let lookback = 7d;
let suspicious_exts = dynamic([".hta", ".lnk", ".iso", ".vhd", ".docm", ".xlsm", ".pptm"]);
